		json.NewEncoder(ctx).Encode(response)
		return
	}

	// Check status code
	if httpResp.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		response := URLPreview{Error: "URL returned non-200 status code"}
		json.NewEncoder(ctx).Encode(response)
		return
	}

	// Parse HTML
	body := httpResp.Body()
	title, description := parseHTML(string(body))

	// Return response
	ctx.SetStatusCode(fasthttp.StatusOK)
	response := URLPreview{
		Title:       title,
		Description: description,
	}
	json.NewEncoder(ctx).Encode(response)
}

func parseHTML(htmlContent string) (title, description string) {
	doc, err := html.Parse(strings.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" || attr.Key == "property" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if (name == "description" || name == "og:description") && description == "" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)

	return strings.TrimSpace(title), strings.TrimSpace(description)
}

func main() {
	handler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			if string(ctx.Method()) == "POST" {
