// extractTitle extracts the title from HTML content
func extractTitle(html string) string {
	// Match <title>...</title> tag (case insensitive, handles newlines)
	re := regexp.MustCompile(`(?i)<title[^>]*>(.*?)</title>`)
	matches := re.FindStringSubmatch(html)
	if len(matches) > 1 {
		title := strings.TrimSpace(matches[1])
		// Decode HTML entities and clean up
		title = cleanHTMLText(title)
		return title
	}
	return ""
}

// extractMetaDescription extracts the meta description from HTML content
func extractMetaDescription(html string) string {
	// Match meta description tag (case insensitive)
	re := regexp.MustCompile(`(?i)<meta[^>]*name=["']description["'][^>]*content=["']([^"']*)["'][^>]*>`)
	matches := re.FindStringSubmatch(html)
	if len(matches) > 1 {
		return cleanHTMLText(matches[1])
	}

	// Try alternate format: content before name
	re = regexp.MustCompile(`(?i)<meta[^>]*content=["']([^"']*)["'][^>]*name=["']description["'][^>]*>`)
	matches = re.FindStringSubmatch(html)
	if len(matches) > 1 {
		return cleanHTMLText(matches[1])
	}

	// Try og:description
	re = regexp.MustCompile(`(?i)<meta[^>]*property=["']og:description["'][^>]*content=["']([^"']*)["'][^>]*>`)
	matches = re.FindStringSubmatch(html)
	if len(matches) > 1 {
		return cleanHTMLText(matches[1])
	}

	return ""
}

// cleanHTMLText removes extra whitespace and decodes basic HTML entities
func cleanHTMLText(text string) string {
	// Replace common HTML entities
	text = strings.ReplaceAll(text, "&amp;", "&")
	text = strings.ReplaceAll(text, "&lt;", "<")
	text = strings.ReplaceAll(text, "&gt;", ">")
	text = strings.ReplaceAll(text, "&quot;", "\"")
	text = strings.ReplaceAll(text, "&#39;", "'")
	text = strings.ReplaceAll(text, "&apos;", "'")

	// Remove extra whitespace
	text = strings.TrimSpace(text)
	re := regexp.MustCompile(`\s+`)
	text = re.ReplaceAllString(text, " ")

	return text
}

func main() {
	// Create request handler
	handler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not Found", fasthttp.StatusNotFound)
		}
	}

	// Start server
	addr := ":8080"
	log.Printf("Server starting on %s", addr)
	log.Printf("POST to http://localhost%s/preview with JSON body: {\"url\": \"https://example.com\"}", addr)

	if err := fasthttp.ListenAndServe(addr, handler); err != nil {
		log.Fatalf("Error in ListenAndServe: %s", err)
	}
}

