	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			// Re-resolve to prevent DNS rebinding
			host, _, err := net.SplitHostPort(addr)
			if err != nil {
				return nil, err
			}

			ips, err := net.LookupIP(host)
			if err != nil {
				return nil, err
			}

			for _, ip := range ips {
				if isPrivateIP(ip) {
