		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL format
	parsedURL, err := url.Parse(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Validate hostname exists
	if parsedURL.Host == "" {
		ctx.Error("URL must have a valid host", fasthttp.StatusBadRequest)
		return
	}

	// Extract hostname for IP validation
	hostname := parsedURL.Hostname()
	if hostname == "" {
		ctx.Error("Invalid hostname", fasthttp.StatusBadRequest)
		return
	}

	// Check if hostname is an IP address and validate it
	if ip := net.ParseIP(hostname); ip != nil {
		if isPrivateOrLocalIP(ip) {
			ctx.Error("Access to private/local IP addresses is not allowed", fasthttp.StatusForbidden)
			return
		}
	} else {
		// Resolve hostname to IP and validate
		ips, err := net.LookupIP(hostname)
		if err != nil {
			ctx.Error("Failed to resolve hostname", fasthttp.StatusBadRequest)
			return
		}

		// Check all resolved IPs
		for _, ip := range ips {
			if isPrivateOrLocalIP(ip) {
				ctx.Error("Access to private/local IP addresses is not allowed", fasthttp.StatusForbidden)
				return
			}
		}
	}

	// Use fasthttp.Client to fetch with timeout and custom dialer
	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			// Re-validate IP at connection time to prevent DNS rebinding
			host, _, err := net.SplitHostPort(addr)
			if err != nil {
				return nil, err
			}

