				return nil, fmt.Errorf("connection blocked: %v", err)
			}
			return fasthttp.DialTimeout(addr, requestTimeout)
		},
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
		MaxResponseBodySize: maxResponseBodySize,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	maxRedirectCounts := 5 // Reduced from 10 to limit redirect chains
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// validateHostSafety checks if the host is safe to connect to (prevents SSRF)
func validateHostSafety(host string) error {
	// Remove port if present
	hostname := host
	if h, _, err := net.SplitHostPort(host); err == nil {
		hostname = h
	}

	// Check for localhost variations
	if isLocalhost(hostname) {
		return fmt.Errorf("connections to localhost are not allowed")
	}

	// Resolve hostname to IP addresses
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname: %v", err)
	}

	// Check each resolved IP
	for _, ip := range ips {
		if isPrivateOrReservedIP(ip) {
			return fmt.Errorf("connections to private or reserved IP addresses are not allowed")
		}
	}

	return nil
}

// isLocalhost checks if hostname is localhost
func isLocalhost(hostname string) bool {
	hostname = strings.ToLower(hostname)
	return hostname == "localhost" ||
		hostname == "127.0.0.1" ||
		hostname == "::1" ||
		hostname == "0.0.0.0" ||
		hostname == "::"
}

// isPrivateOrReservedIP checks if an IP is private, loopback, link-local, or reserved
func isPrivateOrReservedIP(ip net.IP) bool {
	if ip.IsLoopback() {
		return true
	}

	if ip.IsPrivate() {
		return true
	}

	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check for reserved ranges
	// 0.0.0.0/8
	if ip.To4() != nil && ip.To4()[0] == 0 {
		return true
	}

	// 169.254.0.0/16 (link-local, but double-check)
	if ip.To4() != nil && ip.To4()[0] == 169 && ip.To4()[1] == 254 {
		return true
	}

	// 224.0.0.0/4 (multicast)
	if ip.To4() != nil && ip.To4()[0] >= 224 && ip.To4()[0] <= 239 {
		return true
	}

	// 240.0.0.0/4 (reserved)
	if ip.To4() != nil && ip.To4()[0] >= 240 {
		return true
	}

	// IPv6 unique local addresses (fc00::/7)
	if len(ip) == net.IPv6len && ip[0] >= 0xfc && ip[0] <= 0xfd {
		return true
	}

	return false
}

