	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		response := URLPreview{Error: "Failed to fetch URL: " + err.Error()}
		json.NewEncoder(ctx).Encode(response)
		return
	}

	// Check response status
	if httpResp.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		response := URLPreview{Error: "Failed to fetch URL: HTTP status " + strconv.Itoa(httpResp.StatusCode())}
		json.NewEncoder(ctx).Encode(response)
		return
	}

	// Parse HTML
	body := httpResp.Body()
	title, description := parseHTML(body)

	// Return response
	ctx.SetStatusCode(fasthttp.StatusOK)
	response := URLPreview{
		Title:       title,
		Description: description,
	}
	json.NewEncoder(ctx).Encode(response)
}

func parseHTML(body []byte) (string, string) {
	var title, description string

	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" {
				if n.FirstChild != nil {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			} else if n.Data == "meta" {
				var name, content, property string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = strings.ToLower(attr.Val)
					case "property":
						property = strings.ToLower(attr.Val)
					case "content":
						content = attr.Val
					}
				}
				if description == "" && (name == "description" || property == "og:description") {
					description = strings.TrimSpace(content)
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

func main() {
	handler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not Found", fasthttp.StatusNotFound)
		}
	}

	server := &fasthttp.Server{
		Handler: handler,
	}

	println("Server starting on :8080")
	if err := server.ListenAndServe(":8080"); err != nil {
		panic(err)
	}
}

