		return
	}
}

// validateURL checks if the URL is safe to fetch (SSRF protection)
func validateURL(parsedURL *url.URL) error {
	hostname := parsedURL.Hostname()

	// Block localhost and empty hostnames
	if hostname == "" || hostname == "localhost" {
		return fmt.Errorf("localhost access not allowed")
	}

	// Resolve hostname to IP addresses
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname: %w", err)
	}

	// Check each resolved IP
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("private IP addresses not allowed")
		}
	}

	return nil
}

// isPrivateIP checks if an IP is private, loopback, or link-local
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check for private IPv4 ranges
	privateIPBlocks := []string{
		"10.0.0.0/8",     // RFC1918
		"172.16.0.0/12",  // RFC1918
		"192.168.0.0/16", // RFC1918
		"169.254.0.0/16", // RFC3927 link-local
		"127.0.0.0/8",    // IPv4 loopback
		"0.0.0.0/8",      // Current network
		"100.64.0.0/10",  // RFC6598 Shared Address Space
		"fc00::/7",       // IPv6 unique local addr
		"fe80::/10",      // IPv6 link-local
		"::1/128",        // IPv6 loopback
	}

	for _, block := range privateIPBlocks {
		_, subnet, err := net.ParseCIDR(block)
		if err != nil {
			continue
		}
		if subnet.Contains(ip) {
			return true
		}
	}

	return false
}

// dialWithSSRFProtection is a custom dialer that validates IPs before connecting
func dialWithSSRFProtection(addr string) (net.Conn, error) {
	host, _, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	// Resolve and validate the IP
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("connection to private IP not allowed")
		}
	}

	// Use default dialer with timeout
	dialer := &net.Dialer{
		Timeout:   10 * time.Second,
		KeepAlive: 10 * time.Second,
	}

	return dialer.Dial("tcp", addr)
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	return "dummy title", "dummy description", nil
}

