	var req URLRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		response := URLPreview{Error: "Invalid JSON request"}
		json.NewEncoder(ctx).Encode(response)
		return
	}

	// Validate URL
	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		response := URLPreview{Error: "URL is required"}
		json.NewEncoder(ctx).Encode(response)
		return
	}

