		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		response := URLPreview{Error: "URL returned non-200 status code"}
		json.NewEncoder(ctx).Encode(response)
		return
	}

	// Parse HTML content
	body := httpResp.Body()
	title, description := parseHTML(body)

	// Return successful response
	ctx.SetStatusCode(fasthttp.StatusOK)
	response := URLPreview{
