)

// RequestBody represents the incoming JSON request
type RequestBody struct {
	URL string `json:"url"`
}

// ResponseBody represents the JSON response
type ResponseBody struct {
	Success     bool   `json:"success"`
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST requests to fetch URL preview information
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Set response content type
	ctx.Response.Header.Set("Content-Type", "application/json")

	// Check if method is POST
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		response := ResponseBody{
			Success: false,
			Error:   "Method not allowed. Use POST",
		}
		json.NewEncoder(ctx).Encode(response)
		return
	}

	// Parse request body
	var reqBody RequestBody
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		response := ResponseBody{
			Success: false,
			Error:   "Invalid JSON body",
		}
		json.NewEncoder(ctx).Encode(response)
		return
	}

	// Validate URL
	if reqBody.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		response := ResponseBody{
			Success: false,
			Error:   "URL field is required",
		}
		json.NewEncoder(ctx).Encode(response)
		return
	}

	// Create fasthttp client with configuration
	client := &fasthttp.Client{
		Dial:                          fasthttp.DialDualStack,
		ReadTimeout:                   3 * time.Second,
		WriteTimeout:                  3 * time.Second,
		MaxIdleConnDuration:           10 * time.Second,
		MaxIdemponentCallAttempts:     1,
		DisableHeaderNamesNormalizing: false,
	}

	// Prepare request
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Fetch URL with redirects and timeout
	err := client.DoRedirects(req, resp, 10)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		response := ResponseBody{
			Success: false,
			Error:   "Failed to fetch URL: " + err.Error(),
		}
		json.NewEncoder(ctx).Encode(response)
		return
	}

	// Check response status code
	if resp.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		response := ResponseBody{
			Success: false,
			Error:   "URL returned non-200 status code",
		}
		json.NewEncoder(ctx).Encode(response)
		return
	}

	// Parse HTML
	body := resp.Body()
	title, description := parseHTML(body)

	// Return success response
	ctx.SetStatusCode(fasthttp.StatusOK)
	response := ResponseBody{
		Success:     true,
		Title:       title,
		Description: description,
	}
	json.NewEncoder(ctx).Encode(response)
}

// parseHTML extracts title and meta description from HTML content
func parseHTML(htmlContent []byte) (title, description string) {
	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" || attr.Key == "property" {
						name = strings.ToLower(attr.Val)
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if (name == "description" || name == "og:description") && description == "" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)

	return strings.TrimSpace(title), strings.TrimSpace(description)
}

func main() {
	// Create request handler
	handler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not Found", fasthttp.StatusNotFound)
		}
	}

	// Start server
	addr := ":8080"
	println("Server starting on", addr)
	if err := fasthttp.ListenAndServe(addr, handler); err != nil {
		panic(err)
	}
}

