// FetchURLPreview handles the POST request to fetch URL preview
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Set response content type
	ctx.Response.Header.Set("Content-Type", "application/json")

	// Check if method is POST
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		response := ResponseBody{Error: "Method not allowed"}
		json.NewEncoder(ctx).Encode(response)
		return
	}

	// Parse request body
	var reqBody RequestBody
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		response := ResponseBody{Error: "Invalid JSON body"}
		json.NewEncoder(ctx).Encode(response)
		return
	}

	// Validate URL
	if reqBody.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		response := ResponseBody{Error: "URL is required"}
		json.NewEncoder(ctx).Encode(response)
		return
	}

	// Create fasthttp client with custom configuration
	client := &fasthttp.Client{
		Dial:         fasthttp.DialDualStack,
		ReadTimeout:  3 * time.Second,
		WriteTimeout: 3 * time.Second,
	}

	// Prepare request and response
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Fetch URL with redirect support and timeout
	err := client.DoRedirects(req, resp, 10)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		response := ResponseBody{Error: "Failed to fetch URL: " + err.Error()}
		json.NewEncoder(ctx).Encode(response)
		return
	}

	// Check status code
	if resp.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		response := ResponseBody{Error: "URL returned non-200 status code"}
		json.NewEncoder(ctx).Encode(response)
		return
	}

	// Parse HTML
	body := resp.Body()
	title, description := parseHTML(body)

	// Return response
	ctx.SetStatusCode(fasthttp.StatusOK)
	response := ResponseBody{
		Title:       title,
		Description: description,
	}
	json.NewEncoder(ctx).Encode(response)
}

// parseHTML extracts title and meta description from HTML content
func parseHTML(htmlContent []byte) (string, string) {
	var title, description string

	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" || attr.Key == "property" {
						name = strings.ToLower(attr.Val)
					}
					if attr.Key == "content" {
