import (
	"encoding/json"
	"strconv"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

type URLRequest struct {
	URL string `json:"url"`
}

type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Set response content type
	ctx.Response.Header.Set("Content-Type", "application/json")

	// Parse request body
	var req URLRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{
			Error: "Invalid JSON body",
		})
		return
	}

	// Validate URL
	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{
			Error: "URL is required",
		})
		return
	}

	// Create fasthttp client with custom configuration
	client := &fasthttp.Client{
		Dial:         fasthttp.DialDualStack,
		ReadTimeout:  3 * time.Second,
		WriteTimeout: 3 * time.Second,
	}

	// Prepare request
	httpReq := fasthttp.AcquireRequest()
	httpResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(httpReq)
	defer fasthttp.ReleaseResponse(httpResp)

	httpReq.SetRequestURI(req.URL)
	httpReq.Header.SetMethod(fasthttp.MethodGet)
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Fetch URL with redirects and timeout
	err := client.DoRedirects(httpReq, httpResp, 10)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{
			Error: "Failed to fetch URL: " + err.Error(),
		})
		return
	}

	// Check status code
	if httpResp.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{
			Error: "Failed to fetch URL: HTTP status " + strconv.Itoa(httpResp.StatusCode()),
		})
		return
	}

	// Parse HTML
	body := httpResp.Body()
	title, description := parseHTML(body)

	// Return response
	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(URLPreviewResponse{
		Title:       title,
		Description: description,
	})
}

func parseHTML(body []byte) (title, description string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" {
				if n.FirstChild != nil {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			} else if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" || attr.Key == "property" {
						name = strings.ToLower(attr.Val)
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if description == "" && (name == "description" || name == "og:description") {
					description = strings.TrimSpace(content)
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return title, description
}

func main() {
	handler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not Found", fasthttp.StatusNotFound)
		}
	}

	server := &fasthttp.Server{
		Handler: handler,
	}

	println("Server starting on :8080")
	if err := server.ListenAndServe(":8080"); err != nil {
		panic(err)
	}
}

