// extractTitle extracts the title from HTML content
func extractTitle(html string) string {
	// Try to find <title> tag
	titleRegex := regexp.MustCompile(`(?i)<title[^>]*>(.*?)</title>`)
	matches := titleRegex.FindStringSubmatch(html)
	if len(matches) > 1 {
